INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('1', 'general', 'Document Formatting Requirements', '1', 'Font: Times New Roman, Size 12 for body text, Size 14 for chapter numbers/titles. Line Spacing: 1.5. Margins: Top 2.5cm, Bottom 2.5cm, Right 2.5cm, Left 3cm (for binding). Text Alignment: Full justified. Minimum word count: 7,500 ± 10% for undergraduate, 15,000 ± 10% for postgraduate.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('2', 'formatting', 'Cover Page Requirements', '1', 'The cover page must include: University logo (centered), Full dissertation title (uppercase, bold), Student full name, Student registration number, Supervisor name, Faculty and Department, Degree being pursued, Submission date (Month Year format).', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('3', 'formatting', 'Declaration', '2', 'A signed statement declaring: the work is original, it has not been submitted elsewhere, all references are properly cited, and the student accepts responsibility for any issues found.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('4', 'formatting', 'Certificate of Approval', '3', 'Includes: dissertation title, student name, examining committee signatures (supervisor, committee member), date of approval, and university stamp.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('5', 'formatting', 'Abstract', '4', 'A concise summary (200-300 words) covering: research problem, objectives, methodology, key findings, and conclusions. Should be self-contained and give a complete picture of the study.', '200', '300', NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('6', 'formatting', 'Table of Contents', '5', 'Auto-generated using MS Word heading styles. Must include all chapters, sections, and sub-sections with correct page numbers. Separate lists for tables, figures, and abbreviations should follow.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('7', 'topic', 'Topic Formulation Guidelines', '1', 'Research Topic Selection: Choose a topic that is specific, researchable, and relevant to your field. The topic should address a clear gap in existing knowledge. Use the FINER criteria: Feasible (can be completed with available resources), Interesting (contributes to knowledge), Novel (adds something new), Ethical (respects research ethics), Relevant (important to the field and practice).', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('8', 'concept_note', 'Concept Note Requirements', '1', 'The concept note should include: 1) Working title of the dissertation, 2) Brief background and context (200-300 words), 3) Statement of the problem (100-150 words), 4) Research objectives (1 main + 3 specific), 5) Proposed methodology overview (100-150 words), 6) Expected outcomes and significance, 7) Preliminary references (5-10 sources).', NULL, NULL, '2', '3', '1', '2026-03-08 14:02:38', '2026-03-08 14:02:38');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('9', 'chapter1', 'Chapter 1: Introduction', '1', 'Chapter 1 introduces the study and sets the foundation. Required sections: 1.1 Introduction (1-2 pages) - background context; 1.2 Background of the Study (1-3 pages) - detailed context; 1.3 Statement of the Problem (3-4 paragraphs, 200-300 words) - the gap being addressed; 1.4 Research Objectives - 1 main objective + 3 specific objectives (SMART criteria); 1.5 Research Questions or Hypotheses - aligned with objectives; 1.6 Significance/Justification (100-120 words); 1.7 Scope and Limitations (100-120 words); 1.8 Structure of the Dissertation; 1.9 Chapter Summary (60-100 words).', NULL, NULL, '6', '10', '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('10', 'chapter1', 'Research Objectives (SMART)', '2', 'Objectives must follow SMART criteria: Specific (clear about what, who, where), Measurable (can be quantified or observed), Achievable (realistic within scope), Relevant (directly addresses the problem), Time-bound (achievable within study period). Main objective starts with \"To examine/investigate/assess...\" Specific objectives start with action verbs like \"To determine...\", \"To assess...\", \"To examine...\".', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('11', 'chapter1', 'Research Questions & Hypotheses', '3', 'Research Questions: Each specific objective should have a corresponding research question. Hypotheses (if applicable): Each has a null hypothesis (H0) and alternative hypothesis (H1/Ha). Hypotheses are testable predictions about relationships between variables.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('12', 'chapter2', 'Chapter 2: Literature Review', '1', 'Chapter 2 reviews existing literature and theoretical foundations. Sections: 2.1 Introduction; 2.2 Definitions of Key Concepts (max 3 pages) - define 5-8 key terms with 3-5 scholarly definitions each; 2.3 Theoretical Framework (100-150 words per theory, include 2-3 theories); 2.4 Empirical Literature Review (9-12 pages, organized by research objectives, 3-4 pages per objective); 2.5 Conceptual Framework (diagram + narrative); 2.6 Chapter Summary.', NULL, NULL, '15', '25', '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('13', 'chapter2', 'Theoretical Framework Guide', '2', 'For each theory include: 1) Name and primary developer with citation, 2) Historical development, 3) Key principles and assumptions (2-3 core), 4) Relevance to your study and how it connects to your variables, 5) Limitations or critiques (1-2). Connect multiple theories to show a comprehensive framework.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('14', 'chapter2', 'Empirical Literature Review', '3', 'Organize by research objectives (3-4 pages per objective). For each study: identify author/year, explain purpose, describe methodology (sample size, location, design, data collection), summarize key findings, highlight limitations. Use synthesis: compare/contrast findings, identify agreements and contradictions, evaluate methods, identify research gaps your study addresses.', NULL, NULL, '9', '12', '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('15', 'chapter2', 'Conceptual Framework', '4', 'Create a diagram showing: Independent variables (left), Dependent variable (right), arrows showing relationships, any moderating/mediating variables. Include a narrative explanation (1-2 paragraphs) justifying the proposed relationships using theory or literature. Can be original or adapted from existing literature with proper citation.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('16', 'chapter3', 'Chapter 3: Methodology', '1', 'Chapter 3 details the research methodology. Sections: 3.1 Introduction (½ page); 3.2 Participants and Location (2 paragraphs); 3.4 Research Design (1-2 pages) covering Research Philosophy, Research Approach, Methodological Choice, Research Strategy, Time Horizon; 3.4.6 Sampling (1-2 pages); 3.5 Data Collection Tools (1-2 pages); 3.6 Data Collection (1 page); 3.7 Data Analysis (1-2 pages); 3.8 Ethical Considerations (½-1 page); 3.9 Limitations and Delimitations (½ page); 3.10 Chapter Summary (½ page).', NULL, NULL, '8', '15', '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('17', 'chapter3', 'Research Design Components', '2', 'Research Philosophy (100 words): positivism, interpretivism, or pragmatism. Research Approach (100 words): deductive, inductive, or abductive. Methodological Choice (100-150 words): qualitative, quantitative, or mixed methods. Research Strategy (100 words): survey, case study, experiment, etc. Time Horizon: cross-sectional or longitudinal.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('18', 'chapter3', 'Sampling Guidelines', '3', 'Sample Size: For quantitative studies use Yamane formula n = N/(1 + Ne²). Minimum 30 responses for statistical validity. For qualitative, plan 10-15 interviews. Sampling Technique: random, stratified, purposive, or convenience. Justify technique choice and describe recruitment process.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('19', 'chapter3', 'Data Collection & Analysis', '4', 'Tools: questionnaires, interview guides, observation sheets. Pretest with 5-10 participants. Validate using Cronbach alpha (aim for α ≥ 0.7). Analysis: Quantitative - use SPSS (descriptive stats, regression, t-tests). Qualitative - thematic analysis with NVivo. Explain techniques per objective.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('20', 'chapter4', 'Chapter 4: Results and Discussion', '1', 'Chapter 4 presents findings and discusses implications. Sections: 4.1 Introduction (1-2 paragraphs); 4.2 Restatement of Problem and Objectives; 4.3 Demographics (tables + interpretation + literature links); 4.4 Reliability Tests (Cronbach alpha); 4.5 Descriptive Statistics (means, SD); 4.6 Inferential Statistics by Objective (regression, correlations, etc.); 4.7 Hypothesis Tests (if applicable); 4.8 Chapter Summary. Tables: captions above. Figures: captions below.', NULL, NULL, '15', '30', '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('21', 'chapter4', 'Results Presentation Guidelines', '2', 'For each research objective: 1) Restate the objective, 2) Present statistical test results with tables, 3) Interpret results in non-technical language, 4) Connect to literature from Chapter 2, 5) Relate to theoretical framework, 6) Discuss practical implications. Use past tense for findings, present tense for implications.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('22', 'chapter5', 'Chapter 5: Conclusion and Recommendations', '1', 'Chapter 5 concludes the study. Sections: 5.1 Introduction (1-2 paragraphs, 150-200 words); 5.2 Research Conclusions (organized by objective, 150-250 words each, with data + theory + literature links); 5.3 Research Recommendations (3-6 actionable, cost-aware, evidence-based recommendations, 300-500 words total); 5.4 Recommendations for Further Studies (2-4 specific areas); 5.5 Chapter Summary (100-150 words).', NULL, NULL, '5', '10', '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('23', 'chapter5', 'Recommendations Guide', '2', 'Each recommendation must: specify what action to take, who should do it, how to implement it, estimate costs and benefits, be directly linked to a specific finding. Maximum 3-6 recommendations. Also include 2-4 areas for future research addressing limitations identified in your study.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('24', 'references', 'Reference Requirements', '1', 'Harvard citation style. Arranged alphabetically by first author surname. All sources must be within last 10 years. Journal articles within last 5 years. At least 60% must be empirical journal articles. No predatory journals. Use Mendeley or Zotero for management. Every in-text citation must have a reference entry and vice versa.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('25', 'ethics', 'Ethics Form Requirements', '1', 'Required documents: 1) Informed consent form, 2) IRB approval application, 3) Data protection plan, 4) Participant information sheet. Must address: confidentiality, anonymity (unique codes), data storage security, voluntary participation, right to withdraw, and how sensitive information is handled.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_guidelines` (`guideline_id`, `phase`, `section_title`, `section_order`, `content`, `min_word_count`, `max_word_count`, `min_pages`, `max_pages`, `is_active`, `created_at`, `updated_at`) VALUES ('26', 'defense', 'Defense Preparation Guide', '1', 'Prepare a presentation (15-20 minutes) covering: Introduction and problem, objectives, methodology, key findings, conclusions and recommendations. Expect questions on: methodology justification, findings interpretation, limitations, contribution to knowledge. Dress professionally. Bring printed copies of the dissertation for panel members.', NULL, NULL, NULL, NULL, '1', '2026-03-08 14:02:39', '2026-03-08 14:02:39');
INSERT INTO `dissertation_notifications` (`notification_id`, `dissertation_id`, `user_id`, `type`, `title`, `message`, `link`, `is_read`, `created_at`) VALUES ('1', '1', '55', 'supervisor_assigned', 'Supervisor Assigned', 'A supervisor has been assigned to your dissertation. You may now begin Chapter 1.', NULL, '0', '2026-03-08 20:16:56');
