INSERT INTO `exam_questions` (`question_id`, `exam_id`, `section_id`, `parent_question_id`, `sub_label`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('20', '7', NULL, NULL, NULL, '2', 'The median is always the same as the mean.', 'true_false', '[\"True\",\"False\"]', 'False', '5', 'The median and mean are only equal in perfectly symmetric distributions. They can differ, especially in skewed data.', '2', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `section_id`, `parent_question_id`, `sub_label`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('21', '7', NULL, NULL, NULL, '3', 'Which measure of dispersion is most affected by extreme values (outliers)?', 'multiple_choice', '[\"Interquartile Range\",\"Standard Deviation\",\"Range\",\"Median Absolute Deviation\"]', 'Range', '5', 'Range (max - min) is most affected by outliers since it only considers the two extreme values.', '3', '2026-02-23 03:36:25');
INSERT INTO `exam_questions` (`question_id`, `exam_id`, `section_id`, `parent_question_id`, `sub_label`, `question_number`, `question_text`, `question_type`, `options`, `correct_answer`, `marks`, `explanation`, `question_order`, `created_at`) VALUES ('22', '7', NULL, NULL, NULL, '4', 'If the probability of an event occurring is 0.3, what is the probability of it NOT occurring?', 'multiple_choice', '[\"0.3\",\"0.5\",\"0.7\",\"1.0\"]', '0.7', '5', 'P(not A) = 1 - P(A) = 1 - 0.3 = 0.7.', '4', '2026-02-23 03:36:25');
