-- Table: dissertation_deadlines
DROP TABLE IF EXISTS `dissertation_deadlines`;
CREATE TABLE `dissertation_deadlines` (
  `deadline_id` int(11) NOT NULL AUTO_INCREMENT,
  `phase` enum('topic','concept_note','chapter1','chapter2','chapter3','proposal','ethics','defense','chapter4','chapter5','final_draft','final_submission') NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `deadline_date` datetime NOT NULL,
  `academic_year` varchar(20) DEFAULT NULL,
  `program` varchar(100) DEFAULT NULL,
  `program_type` enum('all','degree','professional','masters','doctorate') DEFAULT 'all',
  `is_active` tinyint(1) DEFAULT 1,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`deadline_id`),
  KEY `idx_phase` (`phase`),
  KEY `idx_deadline` (`deadline_date`),
  KEY `idx_active` (`is_active`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: dissertation_defense
DROP TABLE IF EXISTS `dissertation_defense`;
CREATE TABLE `dissertation_defense` (
  `defense_id` int(11) NOT NULL AUTO_INCREMENT,
  `dissertation_id` int(11) NOT NULL,
  `defense_type` enum('proposal','final') DEFAULT 'proposal',
  `defense_date` datetime DEFAULT NULL,
  `venue` varchar(255) DEFAULT NULL,
  `is_virtual` tinyint(1) DEFAULT 0,
  `meeting_link` varchar(500) DEFAULT NULL,
  `panel_members` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Array of {user_id, name, role}' CHECK (json_valid(`panel_members`)),
  `chairperson_id` int(11) DEFAULT NULL,
  `status` enum('scheduled','in_progress','completed','postponed','cancelled') DEFAULT 'scheduled',
  `grade` decimal(5,2) DEFAULT NULL,
  `result` enum('pass','fail','conditional_pass','major_revision') DEFAULT NULL,
  `panel_comments` text DEFAULT NULL,
  `conditions` text DEFAULT NULL COMMENT 'Conditions for conditional pass',
  `presentation_file` varchar(500) DEFAULT NULL,
  `defense_report_path` varchar(500) DEFAULT NULL,
  `conducted_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`defense_id`),
  KEY `idx_dissertation` (`dissertation_id`),
  KEY `idx_status` (`status`),
  KEY `idx_date` (`defense_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

