  `feedback_text` text NOT NULL,
  `feedback_type` enum('comment','approval','revision_request','rejection') DEFAULT 'comment',
  `flagged_sections` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`flagged_sections`)),
  `attachment_path` varchar(500) DEFAULT NULL,
  `is_read` tinyint(1) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`feedback_id`),
  KEY `idx_dissertation` (`dissertation_id`),
  KEY `idx_submission` (`submission_id`),
  KEY `idx_user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: dissertation_guidelines
DROP TABLE IF EXISTS `dissertation_guidelines`;
CREATE TABLE `dissertation_guidelines` (
  `guideline_id` int(11) NOT NULL AUTO_INCREMENT,
