  `max_pages` int(11) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`guideline_id`),
  KEY `idx_phase` (`phase`),
  KEY `idx_order` (`section_order`)
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: dissertation_notifications
DROP TABLE IF EXISTS `dissertation_notifications`;
CREATE TABLE `dissertation_notifications` (
  `notification_id` int(11) NOT NULL AUTO_INCREMENT,
  `dissertation_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `type` enum('submission','feedback','approval','rejection','revision_request','supervisor_assigned','defense_scheduled','defense_result','similarity_report','ethics_update','phase_complete','reminder') NOT NULL,
  `title` varchar(255) NOT NULL,
