) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: dissertation_reference_letters
DROP TABLE IF EXISTS `dissertation_reference_letters`;
CREATE TABLE `dissertation_reference_letters` (
  `letter_id` int(11) NOT NULL AUTO_INCREMENT,
  `dissertation_id` int(11) NOT NULL,
  `student_id` varchar(20) NOT NULL,
  `letter_type` enum('data_collection','case_study','institutional_access','other') DEFAULT 'data_collection',
  `addressed_to` varchar(255) DEFAULT NULL,
  `organization` varchar(255) DEFAULT NULL,
  `purpose` text DEFAULT NULL,
  `study_description` text DEFAULT NULL,
  `data_collection_period` varchar(100) DEFAULT NULL,
  `status` enum('draft','pending','coordinator_approved','registrar_signed','rejected') DEFAULT 'pending',
  `coordinator_approved_by` int(11) DEFAULT NULL,
  `coordinator_approved_at` datetime DEFAULT NULL,
  `coordinator_comments` text DEFAULT NULL,
  `registrar_signed_by` int(11) DEFAULT NULL,
  `registrar_signed_at` datetime DEFAULT NULL,
  `registrar_signature_path` varchar(500) DEFAULT NULL,
  `rejection_reason` text DEFAULT NULL,
  `letter_reference` varchar(50) DEFAULT NULL,
  `generated_file_path` varchar(500) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`letter_id`),
  KEY `idx_dissertation` (`dissertation_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: dissertation_similarity_checks
DROP TABLE IF EXISTS `dissertation_similarity_checks`;
CREATE TABLE `dissertation_similarity_checks` (
  `check_id` int(11) NOT NULL AUTO_INCREMENT,
  `dissertation_id` int(11) NOT NULL,
  `submission_id` int(11) DEFAULT NULL,
  `phase` enum('topic','concept_note','chapter1','chapter2','chapter3','proposal','ethics','chapter4','chapter5','final_draft','final_submission') NOT NULL,
  `similarity_score` decimal(5,2) DEFAULT 0.00 COMMENT 'Percentage 0-100',
  `ai_detection_score` decimal(5,2) DEFAULT 0.00 COMMENT 'Percentage 0-100',
  `similarity_details` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Sources matched, passages flagged' CHECK (json_valid(`similarity_details`)),
  `ai_detection_details` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'AI patterns detected' CHECK (json_valid(`ai_detection_details`)),
  `cross_student_matches` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Other dissertations with matches' CHECK (json_valid(`cross_student_matches`)),
  `total_words_checked` int(11) DEFAULT 0,
  `flagged_words` int(11) DEFAULT 0,
  `status` enum('pending','processing','completed','failed') DEFAULT 'pending',
  `checked_at` datetime DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`check_id`),
  KEY `idx_dissertation` (`dissertation_id`),
  KEY `idx_submission` (`submission_id`),
  KEY `idx_scores` (`similarity_score`,`ai_detection_score`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: dissertation_submissions
DROP TABLE IF EXISTS `dissertation_submissions`;
CREATE TABLE `dissertation_submissions` (
  `submission_id` int(11) NOT NULL AUTO_INCREMENT,
  `dissertation_id` int(11) NOT NULL,
  `phase` enum('topic','concept_note','chapter1','chapter2','chapter3','proposal','ethics','defense','chapter4','chapter5','final_draft','final_submission') NOT NULL,
  `version` int(11) DEFAULT 1,
  `file_path` varchar(500) DEFAULT NULL,
  `file_name` varchar(255) DEFAULT NULL,
  `file_size` int(11) DEFAULT 0,
  `file_type` varchar(255) DEFAULT NULL,
  `submission_text` text DEFAULT NULL COMMENT 'For concept notes or inline text',
  `word_count` int(11) DEFAULT 0,
  `status` enum('draft','submitted','under_review','approved','revision_requested','rejected') DEFAULT 'draft',
  `submitted_at` datetime DEFAULT NULL,
  `reviewed_at` datetime DEFAULT NULL,
  `reviewed_by` int(11) DEFAULT NULL COMMENT 'user_id of reviewer',
  `formatting_check` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`formatting_check`)),
  `formatting_score` decimal(5,2) DEFAULT NULL,
  `similarity_check_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`submission_id`),
  KEY `idx_dissertation` (`dissertation_id`),
  KEY `idx_phase` (`phase`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: dissertations
DROP TABLE IF EXISTS `dissertations`;
CREATE TABLE `dissertations` (
  `dissertation_id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(20) NOT NULL,
  `user_id` int(11) DEFAULT NULL,
  `title` varchar(500) DEFAULT NULL,
  `topic_area` varchar(255) DEFAULT NULL,
  `program` varchar(100) DEFAULT NULL,
  `program_type` enum('degree','professional','masters','doctorate') DEFAULT 'degree',
  `academic_year` varchar(20) DEFAULT NULL,
  `semester` enum('One','Two') DEFAULT NULL,
  `year_of_study` int(11) DEFAULT NULL,
  `status` enum('topic_submission','topic_review','topic_approved','topic_rejected','concept_note','concept_review','concept_approved','concept_rejected','supervisor_assigned','chapter1_writing','chapter1_submitted','chapter1_review','chapter1_approved','chapter1_revision','chapter2_writing','chapter2_submitted','chapter2_review','chapter2_approved','chapter2_revision','chapter3_writing','chapter3_submitted','chapter3_review','chapter3_approved','chapter3_revision','proposal_submitted','proposal_review','proposal_approved','proposal_revision','ethics_submitted','ethics_review','ethics_approved','ethics_revision','defense_listed','defense_scheduled','defense_passed','defense_failed','chapter4_writing','chapter4_submitted','chapter4_review','chapter4_approved','chapter4_revision','chapter5_writing','chapter5_submitted','chapter5_review','chapter5_approved','chapter5_revision','final_draft_submitted','final_draft_review','final_draft_approved','final_draft_revision','final_submitted','completed','archived') DEFAULT 'topic_submission',
  `current_phase` enum('topic','concept_note','chapter1','chapter2','chapter3','proposal','ethics','defense','chapter4','chapter5','final_draft','final_submission') DEFAULT 'topic',
  `supervisor_id` int(11) DEFAULT NULL COMMENT 'lecturers.lecturer_id',
  `co_supervisor_id` int(11) DEFAULT NULL COMMENT 'lecturers.lecturer_id',
  `coordinator_id` int(11) DEFAULT NULL COMMENT 'research_coordinators.coordinator_id',
  `concept_note_text` text DEFAULT NULL,
  `concept_note_file` varchar(255) DEFAULT NULL,
  `topic_submitted_at` datetime DEFAULT NULL,
  `supervisor_assigned_at` datetime DEFAULT NULL,
  `proposal_approved_at` datetime DEFAULT NULL,
  `ethics_approved_at` datetime DEFAULT NULL,
  `defense_date` datetime DEFAULT NULL,
  `defense_grade` decimal(5,2) DEFAULT NULL,
  `defense_result` enum('pass','fail','conditional_pass') DEFAULT NULL,
  `completed_at` datetime DEFAULT NULL,
  `total_word_count` int(11) DEFAULT 0,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`dissertation_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_supervisor` (`supervisor_id`),
  KEY `idx_coordinator` (`coordinator_id`),
  KEY `idx_status` (`status`),
  KEY `idx_phase` (`current_phase`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exam_answers
DROP TABLE IF EXISTS `exam_answers`;
CREATE TABLE `exam_answers` (
  `answer_id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` int(11) NOT NULL,
  `question_id` int(11) NOT NULL,
  `answer_text` longtext DEFAULT NULL,
  `is_correct` tinyint(1) DEFAULT NULL,
  `marks_obtained` decimal(5,2) DEFAULT 0.00,
  `answered_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`answer_id`),
  KEY `idx_session` (`session_id`),
  KEY `idx_question` (`question_id`)
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exam_monitoring
DROP TABLE IF EXISTS `exam_monitoring`;
CREATE TABLE `exam_monitoring` (
  `monitoring_id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` int(11) NOT NULL,
  `event_type` enum('camera_snapshot','tab_visibility_change','fullscreen_exited','session_started','window_blur','window_focus') NOT NULL,
  `event_data` longtext DEFAULT NULL CHECK (json_valid(`event_data`)),
  `snapshot_path` varchar(500) DEFAULT NULL,
  `timestamp` datetime DEFAULT current_timestamp(),
  `ip_address` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`monitoring_id`),
  KEY `idx_session` (`session_id`),
  KEY `idx_timestamp` (`timestamp`)
) ENGINE=InnoDB AUTO_INCREMENT=33 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exam_questions
DROP TABLE IF EXISTS `exam_questions`;
CREATE TABLE `exam_questions` (
  `question_id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_id` int(11) NOT NULL,
  `section_id` int(11) DEFAULT NULL,
  `parent_question_id` int(11) DEFAULT NULL,
  `sub_label` varchar(10) DEFAULT NULL,
  `question_number` int(11) NOT NULL,
  `question_text` longtext NOT NULL,
  `question_type` enum('multiple_choice','true_false','short_answer','essay') DEFAULT 'multiple_choice',
  `options` longtext DEFAULT NULL CHECK (json_valid(`options`)),
  `correct_answer` text DEFAULT NULL,
  `marks` int(11) DEFAULT 1,
  `explanation` text DEFAULT NULL,
  `question_order` int(11) DEFAULT 0,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`question_id`),
  KEY `idx_exam` (`exam_id`),
  KEY `section_id` (`section_id`),
  KEY `parent_question_id` (`parent_question_id`),
  CONSTRAINT `exam_questions_ibfk_1` FOREIGN KEY (`exam_id`) REFERENCES `exams` (`exam_id`) ON DELETE CASCADE,
  CONSTRAINT `exam_questions_ibfk_2` FOREIGN KEY (`section_id`) REFERENCES `exam_sections` (`section_id`) ON DELETE SET NULL,
  CONSTRAINT `exam_questions_ibfk_3` FOREIGN KEY (`parent_question_id`) REFERENCES `exam_questions` (`question_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=361 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exam_results
DROP TABLE IF EXISTS `exam_results`;
CREATE TABLE `exam_results` (
  `result_id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_id` int(11) NOT NULL,
  `student_id` varchar(20) NOT NULL,
  `session_id` int(11) NOT NULL,
  `total_marks` decimal(5,2) DEFAULT NULL,
  `marks_obtained` decimal(5,2) DEFAULT NULL,
  `percentage` decimal(5,2) DEFAULT NULL,
  `grade` varchar(2) DEFAULT NULL,
  `status` enum('passed','failed','incomplete','flagged') DEFAULT 'incomplete',
  `flagged_reason` text DEFAULT NULL,
  `reviewed_by` int(11) DEFAULT NULL,
  `reviewed_at` datetime DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `score` decimal(10,2) NOT NULL DEFAULT 0.00,
  `is_passed` tinyint(1) DEFAULT 0,
  `submitted_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`result_id`),
  KEY `idx_exam` (`exam_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_session` (`session_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exam_sections
DROP TABLE IF EXISTS `exam_sections`;
CREATE TABLE `exam_sections` (
  `section_id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_id` int(11) NOT NULL,
  `section_label` varchar(20) NOT NULL DEFAULT 'A' COMMENT 'e.g. A, B, C',
  `section_title` varchar(255) NOT NULL COMMENT 'e.g. Section A: Short Answer Questions',
  `description` text DEFAULT NULL,
  `section_order` int(11) DEFAULT 0,
  `total_marks` int(11) DEFAULT 0 COMMENT 'total marks for this section',
  `instructions` text DEFAULT NULL COMMENT 'section-specific instructions',
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`section_id`),
  KEY `idx_exam_order` (`exam_id`,`section_order`),
  CONSTRAINT `exam_sections_ibfk_1` FOREIGN KEY (`exam_id`) REFERENCES `exams` (`exam_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: exam_sessions
DROP TABLE IF EXISTS `exam_sessions`;
CREATE TABLE `exam_sessions` (
  `session_id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_id` int(11) NOT NULL,
  `student_id` varchar(20) NOT NULL,
  `token_id` int(11) DEFAULT NULL,
  `started_at` datetime DEFAULT current_timestamp(),
  `submitted_at` datetime DEFAULT NULL,
  `time_remaining` int(11) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `ip_address` varchar(45) DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `browser_info` longtext DEFAULT NULL CHECK (json_valid(`browser_info`)),
  `ended_at` datetime DEFAULT NULL,
  `status` enum('in_progress','completed','abandoned','timed_out') DEFAULT 'in_progress',
  PRIMARY KEY (`session_id`),
  KEY `idx_exam` (`exam_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_token` (`token_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exam_tokens
DROP TABLE IF EXISTS `exam_tokens`;
CREATE TABLE `exam_tokens` (
  `token_id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_id` int(11) NOT NULL,
  `student_id` varchar(20) DEFAULT NULL,
  `token` varchar(64) NOT NULL,
  `is_used` tinyint(1) DEFAULT 0,
  `used_at` datetime DEFAULT NULL,
  `expires_at` datetime NOT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `token_type` enum('single_use','multi_use') DEFAULT 'single_use',
  `used_by` int(11) DEFAULT NULL,
  `created_by` int(11) DEFAULT NULL,
  PRIMARY KEY (`token_id`),
  UNIQUE KEY `token` (`token`),
  KEY `idx_exam` (`exam_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_token` (`token`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: examination_managers
DROP TABLE IF EXISTS `examination_managers`;
CREATE TABLE `examination_managers` (
  `manager_id` int(11) NOT NULL AUTO_INCREMENT,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `department` varchar(50) DEFAULT NULL,
  `position` varchar(50) DEFAULT 'Examination Officer',
  `hire_date` date DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`manager_id`),
  UNIQUE KEY `email` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: exams
DROP TABLE IF EXISTS `exams`;
CREATE TABLE `exams` (
  `exam_id` int(11) NOT NULL AUTO_INCREMENT,
  `exam_code` varchar(20) NOT NULL,
  `exam_name` varchar(200) NOT NULL,
  `course_id` int(11) DEFAULT NULL,
  `lecturer_id` int(11) DEFAULT NULL,
  `exam_manager_id` int(11) DEFAULT NULL,
  `exam_type` enum('mid_term','final','quiz','assignment') DEFAULT 'mid_term',
  `description` text DEFAULT NULL,
  `total_questions` int(11) DEFAULT 0,
  `total_marks` int(11) DEFAULT 100,
  `passing_marks` int(11) DEFAULT 50,
  `duration_minutes` int(11) NOT NULL,
  `start_time` datetime NOT NULL,
  `end_time` datetime NOT NULL,
  `instructions` text DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `shuffle_questions` tinyint(1) DEFAULT 1,
  `shuffle_options` tinyint(1) DEFAULT 1,
  `show_results` tinyint(1) DEFAULT 1,
  `allow_review` tinyint(1) DEFAULT 0,
  `results_published` tinyint(1) NOT NULL DEFAULT 0,
  `require_camera` tinyint(1) DEFAULT 0,
  `require_token` tinyint(1) DEFAULT 0,
  `max_attempts` int(11) DEFAULT 1,
  `created_by` int(11) DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `dean_approved` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`exam_id`),
  UNIQUE KEY `exam_code` (`exam_code`),
  KEY `idx_course` (`course_id`),
  KEY `idx_lecturer` (`lecturer_id`),
  KEY `idx_manager` (`exam_manager_id`),
  CONSTRAINT `exams_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`) ON DELETE SET NULL,
  CONSTRAINT `exams_ibfk_2` FOREIGN KEY (`lecturer_id`) REFERENCES `lecturers` (`lecturer_id`) ON DELETE SET NULL,
  CONSTRAINT `exams_ibfk_3` FOREIGN KEY (`exam_manager_id`) REFERENCES `examination_managers` (`manager_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: faculties
DROP TABLE IF EXISTS `faculties`;
CREATE TABLE `faculties` (
  `faculty_id` int(11) NOT NULL AUTO_INCREMENT,
  `faculty_code` varchar(20) NOT NULL,
  `faculty_name` varchar(255) NOT NULL,
  `head_of_faculty` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`faculty_id`),
  UNIQUE KEY `faculty_code` (`faculty_code`),
  KEY `idx_faculty_code` (`faculty_code`),
  KEY `idx_faculty_name` (`faculty_name`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: fee_settings
DROP TABLE IF EXISTS `fee_settings`;
CREATE TABLE `fee_settings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `application_fee` decimal(10,2) DEFAULT 5500.00,
  `registration_fee` decimal(10,2) DEFAULT 39500.00,
  `new_student_reg_fee` decimal(12,2) DEFAULT 39500.00,
  `continuing_reg_fee` decimal(12,2) DEFAULT 35000.00,
  `tuition_degree` decimal(10,2) DEFAULT 500000.00,
  `tuition_professional` decimal(10,2) DEFAULT 200000.00,
  `tuition_masters` decimal(10,2) DEFAULT 1100000.00,
  `tuition_doctorate` decimal(10,2) DEFAULT 2200000.00,
  `supplementary_exam_fee` decimal(10,2) DEFAULT 50000.00,
  `deferred_exam_fee` decimal(10,2) DEFAULT 50000.00,
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: finance_audit_log
DROP TABLE IF EXISTS `finance_audit_log`;
CREATE TABLE `finance_audit_log` (
  `log_id` int(11) NOT NULL AUTO_INCREMENT,
  `action_type` varchar(50) NOT NULL COMMENT 'payment_entry, payment_approval, payment_rejection, report_access, etc',
  `performed_by` varchar(10) NOT NULL COMMENT 'Finance user ID',
  `finance_role` varchar(20) NOT NULL COMMENT 'Role at time of action',
  `target_student_id` varchar(20) DEFAULT NULL,
  `target_transaction_id` int(11) DEFAULT NULL,
  `amount` decimal(10,2) DEFAULT NULL,
  `action_details` text DEFAULT NULL,
  `ip_address` varchar(45) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`log_id`),
  KEY `idx_action_type` (`action_type`),
  KEY `idx_performed_by` (`performed_by`),
  KEY `idx_student` (`target_student_id`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: finance_users
DROP TABLE IF EXISTS `finance_users`;
CREATE TABLE `finance_users` (
  `finance_id` int(11) NOT NULL AUTO_INCREMENT,
  `finance_code` varchar(20) DEFAULT NULL COMMENT 'e.g., FIN2024001',
  `full_name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `password` varchar(255) DEFAULT NULL,
  `department` varchar(100) DEFAULT 'Finance Department',
  `position` varchar(100) DEFAULT 'Finance Officer',
  `gender` enum('Male','Female','Other') DEFAULT NULL,
  `national_id` varchar(50) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `profile_picture` varchar(255) DEFAULT NULL,
  `hire_date` date DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`finance_id`),
  UNIQUE KEY `email` (`email`),
  UNIQUE KEY `finance_code` (`finance_code`),
  KEY `idx_email` (`email`),
  KEY `idx_finance_code` (`finance_code`),
  KEY `idx_is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: lecturer_finance_requests
DROP TABLE IF EXISTS `lecturer_finance_requests`;
CREATE TABLE `lecturer_finance_requests` (
  `request_id` int(11) NOT NULL AUTO_INCREMENT,
  `lecturer_id` varchar(50) NOT NULL,
  `month` int(11) NOT NULL,
  `year` int(11) NOT NULL,
  `courses_data` text NOT NULL,
  `total_students` int(11) DEFAULT 0,
  `total_modules` int(11) DEFAULT 0,
  `total_assignments_marked` int(11) DEFAULT 0,
  `total_content_uploaded` int(11) DEFAULT 0,
  `total_hours` decimal(10,2) DEFAULT 0.00,
  `hourly_rate` decimal(10,2) DEFAULT 0.00,
  `total_amount` decimal(10,2) DEFAULT 0.00,
  `signature_path` varchar(255) DEFAULT NULL,
  `additional_notes` text DEFAULT NULL,
  `status` enum('pending','approved','rejected','paid') DEFAULT 'pending',
  `odl_approval_status` enum('pending','approved','rejected','returned') DEFAULT 'pending',
  `odl_approved_by` int(11) DEFAULT NULL,
  `odl_approved_at` timestamp NULL DEFAULT NULL,
  `odl_remarks` text DEFAULT NULL,
  `submission_date` datetime DEFAULT NULL,
  `reviewed_date` datetime DEFAULT NULL,
  `admin_notes` text DEFAULT NULL,
  `request_date` timestamp NOT NULL DEFAULT current_timestamp(),
  `response_date` datetime DEFAULT NULL,
  `dean_approval_status` enum('pending','approved','rejected','returned') DEFAULT NULL,
  `dean_approved_by` int(11) DEFAULT NULL,
  `dean_approved_at` datetime DEFAULT NULL,
  `dean_remarks` text DEFAULT NULL,
  PRIMARY KEY (`request_id`),
  KEY `idx_lecturer` (`lecturer_id`),
  KEY `idx_status` (`status`),
  KEY `idx_submission` (`submission_date`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: lecturer_invite_registrations
DROP TABLE IF EXISTS `lecturer_invite_registrations`;
CREATE TABLE `lecturer_invite_registrations` (
  `registration_id` int(11) NOT NULL AUTO_INCREMENT,
  `invite_id` int(11) NOT NULL DEFAULT 0 COMMENT '0 = general registration (no invite)',
  `lecturer_id` int(11) DEFAULT NULL COMMENT 'Set on approval - FK to lecturers',
  `user_id` int(11) DEFAULT NULL COMMENT 'The user_id created (set on approval)',
  `first_name` varchar(100) NOT NULL,
  `middle_name` varchar(100) DEFAULT NULL,
  `last_name` varchar(100) NOT NULL,
  `email` varchar(150) NOT NULL,
  `phone` varchar(30) DEFAULT NULL,
  `gender` varchar(10) DEFAULT NULL,
  `national_id` varchar(20) DEFAULT NULL,
  `department` varchar(100) DEFAULT NULL,
  `position` varchar(50) DEFAULT NULL,
  `qualification` varchar(200) DEFAULT NULL COMMENT 'e.g. PhD, Masters, etc.',
  `specialization` varchar(200) DEFAULT NULL,
  `bio` text DEFAULT NULL,
  `selected_modules` text DEFAULT NULL COMMENT 'JSON array of selected course_ids (max 7)',
  `status` enum('pending','approved','rejected') DEFAULT 'pending',
  `reviewed_by` int(11) DEFAULT NULL COMMENT 'Admin who approved/rejected',
  `reviewed_at` datetime DEFAULT NULL,
  `admin_notes` text DEFAULT NULL,
  `registered_at` timestamp NULL DEFAULT current_timestamp(),
  `ip_address` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`registration_id`),
  KEY `idx_invite` (`invite_id`),
  KEY `idx_lecturer` (`lecturer_id`),
  KEY `idx_status` (`status`),
  KEY `idx_email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: lecturer_registration_invites
DROP TABLE IF EXISTS `lecturer_registration_invites`;
CREATE TABLE `lecturer_registration_invites` (
  `invite_id` int(11) NOT NULL AUTO_INCREMENT,
  `token` varchar(64) NOT NULL,
  `email` varchar(150) DEFAULT NULL COMMENT 'Optional: pre-fill email if sent to specific lecturer',
  `full_name` varchar(150) DEFAULT NULL COMMENT 'Optional: pre-fill name',
  `department` varchar(100) DEFAULT NULL COMMENT 'Optional: pre-assign department',
  `position` varchar(50) DEFAULT NULL COMMENT 'e.g. Lecturer, Senior Lecturer',
  `max_uses` int(11) DEFAULT 1 COMMENT '1 = single use, >1 = multi-use link',
  `times_used` int(11) DEFAULT 0,
  `is_active` tinyint(1) DEFAULT 1,
  `expires_at` datetime DEFAULT NULL COMMENT 'NULL = never expires',
  `created_by` int(11) NOT NULL COMMENT 'FK to users.user_id (admin who created)',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `notes` text DEFAULT NULL COMMENT 'Admin notes about this invite',
  PRIMARY KEY (`invite_id`),
  UNIQUE KEY `token` (`token`),
  KEY `idx_token` (`token`),
  KEY `idx_email` (`email`),
  KEY `idx_active` (`is_active`),
  KEY `idx_created_by` (`created_by`),
  KEY `idx_expires` (`expires_at`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: lecturers
DROP TABLE IF EXISTS `lecturers`;
CREATE TABLE `lecturers` (
  `lecturer_id` int(11) NOT NULL AUTO_INCREMENT,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `password` varchar(255) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `department` varchar(50) DEFAULT NULL,
  `program` varchar(100) DEFAULT NULL,
  `position` varchar(50) DEFAULT NULL,
  `hire_date` date DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `office` varchar(100) DEFAULT NULL,
  `bio` text DEFAULT NULL,
  `profile_picture` varchar(255) DEFAULT NULL,
  `gender` enum('Male','Female','Other') DEFAULT NULL,
  `role` varchar(20) DEFAULT 'lecturer' COMMENT 'staff, finance, lecturer',
  `finance_role` varchar(20) DEFAULT NULL COMMENT 'Finance sub-roles: finance_entry, finance_approval, finance_manager',
  `nrc` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`lecturer_id`),
  UNIQUE KEY `email` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: login_attempts
DROP TABLE IF EXISTS `login_attempts`;
CREATE TABLE `login_attempts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username_email` varchar(255) NOT NULL,
  `ip_address` varchar(45) NOT NULL,
  `user_agent` text DEFAULT NULL,
  `attempt_time` datetime DEFAULT current_timestamp(),
  `success` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `idx_username_email` (`username_email`),
  KEY `idx_ip_address` (`ip_address`),
  KEY `idx_attempt_time` (`attempt_time`)
) ENGINE=InnoDB AUTO_INCREMENT=398 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: login_history
DROP TABLE IF EXISTS `login_history`;
CREATE TABLE `login_history` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `ip_address` varchar(45) NOT NULL,
  `user_agent` text DEFAULT NULL,
  `device_info` varchar(255) DEFAULT NULL,
  `location` varchar(255) DEFAULT NULL,
  `login_time` datetime DEFAULT current_timestamp(),
  `logout_time` datetime DEFAULT NULL,
  `session_duration` int(11) DEFAULT 0,
  `is_suspicious` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_login_time` (`login_time`),
  CONSTRAINT `login_history_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=309 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: modules
DROP TABLE IF EXISTS `modules`;
CREATE TABLE `modules` (
  `module_id` int(11) NOT NULL AUTO_INCREMENT,
  `module_code` varchar(20) NOT NULL,
  `module_name` varchar(200) NOT NULL,
  `program_of_study` varchar(100) DEFAULT NULL,
  `year_of_study` int(11) DEFAULT NULL,
  `semester` enum('One','Two') DEFAULT NULL,
  `credits` int(11) DEFAULT 3,
  `description` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`module_id`),
  UNIQUE KEY `module_code` (`module_code`),
  KEY `idx_program` (`program_of_study`),
  KEY `idx_year` (`year_of_study`),
  KEY `idx_semester` (`semester`)
) ENGINE=InnoDB AUTO_INCREMENT=86 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: odl_claims_approval
DROP TABLE IF EXISTS `odl_claims_approval`;
CREATE TABLE `odl_claims_approval` (
  `approval_id` int(11) NOT NULL AUTO_INCREMENT,
  `request_id` int(11) NOT NULL COMMENT 'FK to lecturer_finance_requests',
  `coordinator_id` int(11) NOT NULL COMMENT 'FK to odl_coordinators',
  `status` enum('pending','approved','rejected','returned') DEFAULT 'pending',
  `remarks` text DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`approval_id`),
  KEY `idx_request` (`request_id`),
  KEY `idx_coordinator` (`coordinator_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: odl_coordinators
DROP TABLE IF EXISTS `odl_coordinators`;
CREATE TABLE `odl_coordinators` (
  `coordinator_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(150) NOT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `department` varchar(100) DEFAULT NULL,
  `position` varchar(100) DEFAULT 'ODL Coordinator',
  `campus` varchar(50) DEFAULT 'all',
  `profile_picture` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`coordinator_id`),
  UNIQUE KEY `unique_user` (`user_id`),
  KEY `idx_email` (`email`),
  KEY `idx_active` (`is_active`),
  KEY `idx_campus` (`campus`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: odl_reports
DROP TABLE IF EXISTS `odl_reports`;
CREATE TABLE `odl_reports` (
  `report_id` int(11) NOT NULL AUTO_INCREMENT,
  `report_type` varchar(50) NOT NULL COMMENT 'student_activity, claims_summary, exam_results, enrollment',
  `report_name` varchar(255) NOT NULL,
  `generated_by` int(11) NOT NULL,
  `parameters` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`parameters`)),
  `file_path` varchar(500) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`report_id`),
  KEY `idx_type` (`report_type`),
  KEY `idx_generated_by` (`generated_by`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: password_reset_requests
DROP TABLE IF EXISTS `password_reset_requests`;
CREATE TABLE `password_reset_requests` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `username` varchar(255) NOT NULL,
  `email` varchar(255) NOT NULL,
  `role` varchar(50) NOT NULL,
  `requested_at` datetime DEFAULT current_timestamp(),
  `status` varchar(20) DEFAULT 'pending',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: payment_approvals
DROP TABLE IF EXISTS `payment_approvals`;
CREATE TABLE `payment_approvals` (
  `approval_id` int(11) NOT NULL AUTO_INCREMENT,
  `transaction_id` int(11) NOT NULL,
  `student_id` varchar(20) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `payment_type` varchar(50) NOT NULL,
  `entered_by` varchar(10) NOT NULL COMMENT 'Finance clerk who entered the payment',
  `entered_at` datetime NOT NULL DEFAULT current_timestamp(),
  `approved_by` varchar(10) DEFAULT NULL COMMENT 'Finance approver who approved',
  `approved_at` datetime DEFAULT NULL,
  `rejected_by` varchar(10) DEFAULT NULL,
  `rejected_at` datetime DEFAULT NULL,
  `rejection_reason` text DEFAULT NULL,
  `status` enum('pending','approved','rejected') DEFAULT 'pending',
  `notes` text DEFAULT NULL,
  PRIMARY KEY (`approval_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_status` (`status`),
  KEY `idx_entered_by` (`entered_by`),
  KEY `transaction_id` (`transaction_id`),
  CONSTRAINT `payment_approvals_ibfk_1` FOREIGN KEY (`transaction_id`) REFERENCES `payment_transactions` (`transaction_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: payment_deadline_reminders
DROP TABLE IF EXISTS `payment_deadline_reminders`;
CREATE TABLE `payment_deadline_reminders` (
  `reminder_id` int(11) NOT NULL AUTO_INCREMENT,
  `deadline_id` int(11) NOT NULL,
  `student_id` varchar(50) NOT NULL,
  `reminder_type` varchar(30) NOT NULL COMMENT '10_days, 5_days, 2_days, on_day, 1_day_after, 2_days_after',
  `reminder_message` text DEFAULT NULL,
  `notification_id` int(11) DEFAULT NULL COMMENT 'Link to vle_notifications',
  `email_sent` tinyint(1) DEFAULT 0,
  `sent_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`reminder_id`),
  KEY `idx_deadline_student` (`deadline_id`,`student_id`),
  KEY `idx_reminder_type` (`reminder_type`),
  CONSTRAINT `payment_deadline_reminders_ibfk_1` FOREIGN KEY (`deadline_id`) REFERENCES `payment_deadlines` (`deadline_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: payment_deadlines
DROP TABLE IF EXISTS `payment_deadlines`;
CREATE TABLE `payment_deadlines` (
  `deadline_id` int(11) NOT NULL AUTO_INCREMENT,
  `academic_year` varchar(20) NOT NULL DEFAULT '2025/2026',
  `semester` int(11) NOT NULL DEFAULT 1,
  `installment_type` varchar(50) NOT NULL COMMENT 'application_fee, registration_fee, installment_1-4',
  `installment_label` varchar(100) NOT NULL,
  `deadline_date` date NOT NULL,
  `clearance_deadline` date DEFAULT NULL COMMENT 'Clearance deadline before this installment',
  `amount_expected` decimal(12,2) DEFAULT 0.00,
  `reminder_message` text DEFAULT NULL COMMENT 'Custom message for reminders',
  `program_type` varchar(50) DEFAULT 'all' COMMENT 'all, weekday, weekend',
  `is_active` tinyint(1) DEFAULT 1,
  `created_by` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`deadline_id`),
  KEY `idx_deadline_date` (`deadline_date`),
  KEY `idx_academic_year` (`academic_year`,`semester`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: payment_submissions
DROP TABLE IF EXISTS `payment_submissions`;
CREATE TABLE `payment_submissions` (
  `submission_id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(50) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `payment_reference` varchar(100) DEFAULT NULL,
  `transaction_date` date DEFAULT NULL,
  `proof_of_payment` varchar(255) DEFAULT NULL,
  `transaction_type` varchar(50) DEFAULT NULL,
  `bank_name` varchar(100) DEFAULT NULL,
  `submission_date` timestamp NOT NULL DEFAULT current_timestamp(),
  `status` enum('pending','approved','rejected') DEFAULT 'pending',
  `reviewed_by` varchar(50) DEFAULT NULL,
  `reviewed_date` timestamp NULL DEFAULT NULL,
  `finance_id` int(11) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  PRIMARY KEY (`submission_id`),
  KEY `idx_student_status` (`student_id`,`status`),
  KEY `idx_status` (`status`),
  CONSTRAINT `payment_submissions_ibfk_1` FOREIGN KEY (`student_id`) REFERENCES `students` (`student_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: payment_transactions
DROP TABLE IF EXISTS `payment_transactions`;
CREATE TABLE `payment_transactions` (
  `transaction_id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(50) NOT NULL,
  `payment_type` varchar(50) NOT NULL COMMENT 'Registration, Installment 1-4',
  `amount` decimal(10,2) NOT NULL,
  `payment_method` varchar(50) DEFAULT 'Cash',
  `reference_number` varchar(100) DEFAULT NULL,
  `payment_date` date NOT NULL,
  `recorded_by` varchar(100) NOT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `approval_status` enum('pending','approved','rejected') DEFAULT 'approved' COMMENT 'Payment approval status',
  `approved_by` varchar(10) DEFAULT NULL COMMENT 'Finance user who approved',
  `approved_at` datetime DEFAULT NULL COMMENT 'When payment was approved',
  PRIMARY KEY (`transaction_id`),
  KEY `idx_student_id` (`student_id`),
  KEY `idx_payment_date` (`payment_date`)
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: programs
DROP TABLE IF EXISTS `programs`;
CREATE TABLE `programs` (
  `program_id` int(11) NOT NULL AUTO_INCREMENT,
  `program_code` varchar(10) NOT NULL,
  `program_name` varchar(255) NOT NULL,
  `department_id` int(11) DEFAULT NULL,
  `program_type` enum('degree','professional','masters','doctorate') DEFAULT 'degree',
  `duration_years` int(11) DEFAULT 4,
  `description` text DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`program_id`),
  UNIQUE KEY `program_code` (`program_code`),
  KEY `idx_program_code` (`program_code`),
  KEY `idx_department` (`department_id`),
  KEY `idx_is_active` (`is_active`),
  CONSTRAINT `programs_ibfk_1` FOREIGN KEY (`department_id`) REFERENCES `departments` (`department_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=71 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: registrar_signatures
DROP TABLE IF EXISTS `registrar_signatures`;
CREATE TABLE `registrar_signatures` (
  `signature_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `signatory_name` varchar(255) NOT NULL,
  `signatory_title` varchar(255) DEFAULT 'University Registrar',
  `signature_image_path` varchar(500) NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`signature_id`),
  KEY `idx_user` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: research_coordinators
DROP TABLE IF EXISTS `research_coordinators`;
CREATE TABLE `research_coordinators` (
  `coordinator_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `department` varchar(50) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`coordinator_id`),
  UNIQUE KEY `unique_user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: semester_courses
DROP TABLE IF EXISTS `semester_courses`;
CREATE TABLE `semester_courses` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) NOT NULL,
  `semester` varchar(50) NOT NULL,
  `academic_year` varchar(50) NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_course_semester` (`course_id`,`semester`,`academic_year`),
  CONSTRAINT `semester_courses_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=41 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: smtp_settings
DROP TABLE IF EXISTS `smtp_settings`;
CREATE TABLE `smtp_settings` (
  `setting_id` int(11) NOT NULL AUTO_INCREMENT,
  `smtp_host` varchar(255) NOT NULL DEFAULT 'smtp.gmail.com',
  `smtp_port` int(11) NOT NULL DEFAULT 587,
  `smtp_username` varchar(255) NOT NULL,
  `smtp_password` varchar(255) NOT NULL,
  `smtp_encryption` enum('tls','ssl','none') DEFAULT 'tls',
  `smtp_from_email` varchar(255) NOT NULL,
  `smtp_from_name` varchar(255) DEFAULT 'VLE System',
  `smtp_reply_to_email` varchar(255) DEFAULT NULL,
  `smtp_reply_to_name` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `enable_email_notifications` tinyint(1) DEFAULT 1,
  `test_email_sent` tinyint(1) DEFAULT 0,
  `last_test_date` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`setting_id`),
  KEY `is_active` (`is_active`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: student_access_logs
DROP TABLE IF EXISTS `student_access_logs`;
CREATE TABLE `student_access_logs` (
  `log_id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(50) NOT NULL,
  `course_id` int(11) DEFAULT NULL,
  `content_type` varchar(50) DEFAULT NULL COMMENT 'login, course_view, assignment, content, exam',
  `content_id` int(11) DEFAULT NULL,
  `ip_address` varchar(45) DEFAULT NULL,
  `user_agent` text DEFAULT NULL,
  `accessed_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`log_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_course` (`course_id`),
  KEY `idx_type` (`content_type`),
  KEY `idx_date` (`accessed_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: student_finances
DROP TABLE IF EXISTS `student_finances`;
CREATE TABLE `student_finances` (
  `finance_id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(50) NOT NULL,
  `application_fee_paid` decimal(10,2) DEFAULT 0.00,
  `application_fee_date` date DEFAULT NULL,
  `registration_fee` decimal(10,2) DEFAULT 39500.00,
  `registration_paid` decimal(10,2) DEFAULT 0.00,
  `registration_paid_date` date DEFAULT NULL,
  `expected_tuition` decimal(10,2) DEFAULT 500000.00,
  `expected_total` decimal(10,2) DEFAULT 545000.00,
  `tuition_fee` decimal(10,2) DEFAULT 500000.00,
  `tuition_paid` decimal(10,2) DEFAULT 0.00,
  `installment_1` decimal(10,2) DEFAULT 0.00,
  `installment_1_date` date DEFAULT NULL,
  `installment_2` decimal(10,2) DEFAULT 0.00,
  `installment_2_date` date DEFAULT NULL,
  `installment_3` decimal(10,2) DEFAULT 0.00,
  `installment_3_date` date DEFAULT NULL,
  `installment_4` decimal(10,2) DEFAULT 0.00,
  `installment_4_date` date DEFAULT NULL,
  `total_paid` decimal(10,2) DEFAULT 0.00,
  `balance` decimal(10,2) DEFAULT 539500.00,
  `payment_percentage` int(11) DEFAULT 0,
  `content_access_weeks` int(11) DEFAULT 0 COMMENT 'Weeks of content student can access',
  `last_payment_date` date DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`finance_id`),
  KEY `idx_student_id` (`student_id`),
  KEY `idx_payment_percentage` (`payment_percentage`)
) ENGINE=InnoDB AUTO_INCREMENT=26 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: student_invite_registrations
DROP TABLE IF EXISTS `student_invite_registrations`;
CREATE TABLE `student_invite_registrations` (
  `registration_id` int(11) NOT NULL AUTO_INCREMENT,
  `invite_id` int(11) NOT NULL DEFAULT 0,
  `student_id` varchar(50) DEFAULT NULL,
  `student_id_number` varchar(50) DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `first_name` varchar(100) NOT NULL,
  `middle_name` varchar(100) DEFAULT NULL,
  `last_name` varchar(100) NOT NULL,
  `preferred_username` varchar(100) DEFAULT NULL,
  `email` varchar(150) NOT NULL,
  `phone` varchar(30) DEFAULT NULL,
  `gender` varchar(10) DEFAULT NULL,
  `national_id` varchar(20) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `department_id` int(11) DEFAULT NULL,
  `program` varchar(200) DEFAULT NULL,
  `program_type` varchar(50) DEFAULT 'degree',
  `campus` varchar(100) DEFAULT 'Mzuzu Campus',
  `year_of_registration` int(11) DEFAULT NULL,
  `year_of_study` int(11) DEFAULT 1,
  `semester` varchar(10) DEFAULT 'One',
  `entry_type` varchar(10) DEFAULT 'NE',
  `student_type` varchar(30) DEFAULT 'new_student',
  `selected_modules` text DEFAULT NULL COMMENT 'JSON array of course IDs',
  `status` enum('pending','approved','rejected') DEFAULT 'pending',
  `reviewed_by` int(11) DEFAULT NULL,
  `reviewed_at` datetime DEFAULT NULL,
  `admin_notes` text DEFAULT NULL,
  `registered_at` timestamp NULL DEFAULT current_timestamp(),
  `ip_address` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`registration_id`),
  KEY `idx_invite` (`invite_id`),
  KEY `idx_student` (`student_id`),
  KEY `idx_status` (`status`),
  KEY `idx_email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table: student_registration_invites
DROP TABLE IF EXISTS `student_registration_invites`;
CREATE TABLE `student_registration_invites` (
  `invite_id` int(11) NOT NULL AUTO_INCREMENT,
  `token` varchar(64) NOT NULL,
  `email` varchar(150) DEFAULT NULL,
  `full_name` varchar(150) DEFAULT NULL,
  `department_id` int(11) DEFAULT NULL,
  `program` varchar(200) DEFAULT NULL,
  `campus` varchar(100) DEFAULT NULL,
  `program_type` varchar(50) DEFAULT 'degree',
  `year_of_study` int(11) DEFAULT 1,
  `semester` varchar(10) DEFAULT 'One',
  `entry_type` varchar(10) DEFAULT 'NE',
  `max_uses` int(11) DEFAULT 1,
  `times_used` int(11) DEFAULT 0,
  `is_active` tinyint(1) DEFAULT 1,
  `expires_at` datetime DEFAULT NULL,
  `created_by` int(11) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `notes` text DEFAULT NULL,
  PRIMARY KEY (`invite_id`),
  UNIQUE KEY `token` (`token`),
  KEY `idx_token` (`token`),
  KEY `idx_email` (`email`),
  KEY `idx_active` (`is_active`),
  KEY `idx_created_by` (`created_by`),
  KEY `idx_expires` (`expires_at`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: students
DROP TABLE IF EXISTS `students`;
CREATE TABLE `students` (
  `student_id` varchar(20) NOT NULL,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(100) NOT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `department` varchar(50) DEFAULT NULL,
  `program_type` enum('degree','professional','masters','doctorate') DEFAULT 'degree',
  `program` varchar(100) DEFAULT NULL,
  `year_of_study` int(11) DEFAULT NULL,
  `enrollment_date` date DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `address` text DEFAULT NULL,
  `profile_picture` varchar(255) DEFAULT NULL,
  `campus` varchar(50) DEFAULT 'Mzuzu Campus',
  `year_of_registration` year(4) DEFAULT NULL,
  `semester` enum('One','Two') DEFAULT 'One',
  `academic_level` varchar(10) DEFAULT '1/1',
  `gender` enum('Male','Female','Other') DEFAULT NULL,
  `national_id` varchar(50) DEFAULT NULL,
  `entry_type` varchar(10) DEFAULT 'NE' COMMENT 'ME=Mature Entry, NE=Normal Entry, ODL=Open Distance Learning, PC=Professional Course',
  `student_type` enum('new_student','continuing') DEFAULT 'new_student',
  `student_status` enum('active','graduated','suspended','withdrawn') DEFAULT 'active',
  `graduation_date` date DEFAULT NULL,
  PRIMARY KEY (`student_id`),
  UNIQUE KEY `email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: super_user_login_attempts
DROP TABLE IF EXISTS `super_user_login_attempts`;
CREATE TABLE `super_user_login_attempts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) DEFAULT NULL,
  `ip_address` varchar(45) DEFAULT NULL,
  `success` tinyint(1) DEFAULT NULL,
  `attempted_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: super_users
DROP TABLE IF EXISTS `super_users`;
CREATE TABLE `super_users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `full_name` varchar(100) NOT NULL,
  `email` varchar(100) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `last_login` datetime DEFAULT NULL,
  `login_count` int(11) DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: university_settings
DROP TABLE IF EXISTS `university_settings`;
CREATE TABLE `university_settings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `university_name` varchar(255) NOT NULL DEFAULT 'Exploits University',
  `address_po_box` varchar(100) DEFAULT 'P.O.Box 301752',
  `address_area` varchar(100) DEFAULT 'Area 4',
  `address_street` varchar(100) DEFAULT '',
  `address_city` varchar(100) DEFAULT 'Lilongwe',
  `address_country` varchar(100) DEFAULT 'Malawi',
  `phone` varchar(50) DEFAULT '',
  `email` varchar(100) DEFAULT '',
  `website` varchar(100) DEFAULT '',
  `logo_path` varchar(255) DEFAULT '',
  `receipt_footer_text` text DEFAULT 'Thank you for your payment',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: users
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `user_id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `email` varchar(100) NOT NULL,
  `password_hash` varchar(255) NOT NULL,
  `role` enum('student','lecturer','staff','hod','dean','finance','admin','odl_coordinator','examination_manager','examination_officer','research_coordinator') NOT NULL DEFAULT 'student',
  `additional_roles` varchar(255) DEFAULT NULL,
  `related_student_id` varchar(20) DEFAULT NULL,
  `related_lecturer_id` int(11) DEFAULT NULL,
  `related_staff_id` int(11) DEFAULT NULL,
  `related_hod_id` int(11) DEFAULT NULL,
  `related_dean_id` int(11) DEFAULT NULL,
  `related_finance_id` int(11) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `last_login` datetime DEFAULT NULL,
  `must_change_password` tinyint(1) NOT NULL DEFAULT 0,
  `failed_login_attempts` int(11) DEFAULT 0,
  `last_failed_login` datetime DEFAULT NULL,
  `account_locked_until` datetime DEFAULT NULL,
  `last_login_at` datetime DEFAULT NULL,
  `last_login_ip` varchar(45) DEFAULT NULL,
  PRIMARY KEY (`user_id`),
  UNIQUE KEY `username` (`username`),
  UNIQUE KEY `email` (`email`)
) ENGINE=InnoDB AUTO_INCREMENT=67 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_announcements
DROP TABLE IF EXISTS `vle_announcements`;
CREATE TABLE `vle_announcements` (
  `announcement_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) NOT NULL,
  `lecturer_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `content` text NOT NULL,
  `created_date` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`announcement_id`),
  KEY `course_id` (`course_id`),
  KEY `lecturer_id` (`lecturer_id`),
  CONSTRAINT `vle_announcements_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`) ON DELETE CASCADE,
  CONSTRAINT `vle_announcements_ibfk_2` FOREIGN KEY (`lecturer_id`) REFERENCES `lecturers` (`lecturer_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_assignment_answers
DROP TABLE IF EXISTS `vle_assignment_answers`;
CREATE TABLE `vle_assignment_answers` (
  `answer_id` int(11) NOT NULL AUTO_INCREMENT,
  `question_id` int(11) NOT NULL,
  `assignment_id` int(11) NOT NULL,
  `student_id` varchar(20) NOT NULL,
  `answer_text` mediumtext DEFAULT NULL,
  `is_correct` tinyint(1) DEFAULT NULL,
  `submitted_date` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`answer_id`),
  KEY `question_id` (`question_id`),
  KEY `assignment_id` (`assignment_id`),
  KEY `student_id` (`student_id`)
) ENGINE=MyISAM AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_assignment_questions
DROP TABLE IF EXISTS `vle_assignment_questions`;
CREATE TABLE `vle_assignment_questions` (
  `question_id` int(11) NOT NULL AUTO_INCREMENT,
  `assignment_id` int(11) NOT NULL,
  `question_text` text NOT NULL,
  `question_type` enum('multiple_choice','true_false','short_answer','open_ended','checkboxes','dropdown','essay','paragraph') DEFAULT 'short_answer',
  `options` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `correct_answer` text DEFAULT NULL,
  `marks` int(11) DEFAULT 1,
  `section_id` int(11) DEFAULT NULL,
  `parent_question_id` int(11) DEFAULT NULL,
  `sub_label` varchar(10) DEFAULT NULL,
  `question_order` int(11) DEFAULT 0,
  `is_required` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`question_id`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_assignments
DROP TABLE IF EXISTS `vle_assignments`;
CREATE TABLE `vle_assignments` (
  `assignment_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) DEFAULT NULL,
  `week_number` int(11) DEFAULT NULL,
  `title` varchar(200) NOT NULL,
  `description` text DEFAULT NULL,
  `assignment_type` enum('formative','summative','mid_sem','final_exam') DEFAULT 'formative',
  `max_score` int(11) DEFAULT 100,
  `passing_score` int(11) DEFAULT 50,
  `due_date` datetime DEFAULT NULL,
  `file_path` varchar(500) DEFAULT NULL,
  `file_name` varchar(255) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_date` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`assignment_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `vle_assignments_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1886 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_courses
DROP TABLE IF EXISTS `vle_courses`;
CREATE TABLE `vle_courses` (
  `course_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_code` varchar(20) NOT NULL,
  `course_name` varchar(100) NOT NULL,
  `description` text DEFAULT NULL,
  `lecturer_id` int(11) DEFAULT NULL,
  `program_of_study` varchar(100) DEFAULT NULL,
  `year_of_study` int(11) DEFAULT NULL,
  `applicable_years` varchar(50) DEFAULT NULL,
  `semester` enum('One','Two','Both') DEFAULT 'One',
  `total_weeks` int(11) DEFAULT 16,
  `is_active` tinyint(1) DEFAULT 1,
  `created_date` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`course_id`),
  UNIQUE KEY `course_code` (`course_code`),
  KEY `lecturer_id` (`lecturer_id`),
  CONSTRAINT `vle_courses_ibfk_1` FOREIGN KEY (`lecturer_id`) REFERENCES `lecturers` (`lecturer_id`)
) ENGINE=InnoDB AUTO_INCREMENT=163 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_enrollments
DROP TABLE IF EXISTS `vle_enrollments`;
CREATE TABLE `vle_enrollments` (
  `enrollment_id` int(11) NOT NULL AUTO_INCREMENT,
  `student_id` varchar(20) NOT NULL,
  `course_id` int(11) DEFAULT NULL,
  `enrollment_date` datetime DEFAULT current_timestamp(),
  `current_week` int(11) DEFAULT 1,
  `is_completed` tinyint(1) DEFAULT 0,
  `completion_date` datetime DEFAULT NULL,
  PRIMARY KEY (`enrollment_id`),
  UNIQUE KEY `student_id` (`student_id`,`course_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `vle_enrollments_ibfk_1` FOREIGN KEY (`student_id`) REFERENCES `students` (`student_id`) ON DELETE CASCADE,
  CONSTRAINT `vle_enrollments_ibfk_2` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`)
) ENGINE=InnoDB AUTO_INCREMENT=116 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_forum_posts
DROP TABLE IF EXISTS `vle_forum_posts`;
CREATE TABLE `vle_forum_posts` (
  `post_id` int(11) NOT NULL AUTO_INCREMENT,
  `forum_id` int(11) DEFAULT NULL,
  `parent_post_id` int(11) DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `title` varchar(200) DEFAULT NULL,
  `content` text NOT NULL,
  `post_date` datetime DEFAULT current_timestamp(),
  `is_pinned` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`post_id`),
  KEY `forum_id` (`forum_id`),
  KEY `parent_post_id` (`parent_post_id`),
  KEY `user_id` (`user_id`),
  CONSTRAINT `vle_forum_posts_ibfk_1` FOREIGN KEY (`forum_id`) REFERENCES `vle_forums` (`forum_id`),
  CONSTRAINT `vle_forum_posts_ibfk_2` FOREIGN KEY (`parent_post_id`) REFERENCES `vle_forum_posts` (`post_id`),
  CONSTRAINT `vle_forum_posts_ibfk_3` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_forums
DROP TABLE IF EXISTS `vle_forums`;
CREATE TABLE `vle_forums` (
  `forum_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) DEFAULT NULL,
  `week_number` int(11) DEFAULT NULL,
  `title` varchar(200) NOT NULL,
  `description` text DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_date` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`forum_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `vle_forums_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_grades
DROP TABLE IF EXISTS `vle_grades`;
CREATE TABLE `vle_grades` (
  `grade_id` int(11) NOT NULL AUTO_INCREMENT,
  `enrollment_id` int(11) DEFAULT NULL,
  `assignment_id` int(11) DEFAULT NULL,
  `grade_type` enum('formative','summative','mid_sem','final_exam','overall') NOT NULL,
  `score` decimal(5,2) DEFAULT NULL,
  `max_score` decimal(5,2) DEFAULT NULL,
  `percentage` decimal(5,2) DEFAULT NULL,
  `grade_letter` varchar(2) DEFAULT NULL,
  `graded_date` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`grade_id`),
  KEY `enrollment_id` (`enrollment_id`),
  KEY `assignment_id` (`assignment_id`),
  CONSTRAINT `vle_grades_ibfk_1` FOREIGN KEY (`enrollment_id`) REFERENCES `vle_enrollments` (`enrollment_id`),
  CONSTRAINT `vle_grades_ibfk_2` FOREIGN KEY (`assignment_id`) REFERENCES `vle_assignments` (`assignment_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_live_sessions
DROP TABLE IF EXISTS `vle_live_sessions`;
CREATE TABLE `vle_live_sessions` (
  `session_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) NOT NULL,
  `lecturer_id` varchar(50) NOT NULL,
  `session_name` varchar(255) NOT NULL,
  `session_code` varchar(50) NOT NULL,
  `status` enum('pending','active','completed') DEFAULT 'pending',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `started_at` timestamp NULL DEFAULT NULL,
  `ended_at` timestamp NULL DEFAULT NULL,
  `max_participants` int(11) DEFAULT 50,
  `meeting_url` varchar(500) DEFAULT NULL,
  `recording_url` varchar(500) DEFAULT NULL,
  PRIMARY KEY (`session_id`),
  UNIQUE KEY `session_code` (`session_code`),
  KEY `idx_course` (`course_id`),
  KEY `idx_lecturer` (`lecturer_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=39 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_messages
DROP TABLE IF EXISTS `vle_messages`;
CREATE TABLE `vle_messages` (
  `message_id` int(11) NOT NULL AUTO_INCREMENT,
  `sender_type` enum('student','lecturer','admin','finance') NOT NULL,
  `sender_id` varchar(50) NOT NULL,
  `recipient_type` enum('student','lecturer','admin','finance') NOT NULL,
  `recipient_id` varchar(50) NOT NULL,
  `subject` varchar(200) NOT NULL,
  `message` text NOT NULL,
  `is_read` tinyint(1) DEFAULT 0,
  `sent_date` datetime DEFAULT current_timestamp(),
  `read_date` datetime DEFAULT NULL,
  PRIMARY KEY (`message_id`),
  KEY `recipient_type` (`recipient_type`,`recipient_id`),
  KEY `sender_type` (`sender_type`,`sender_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_notifications
DROP TABLE IF EXISTS `vle_notifications`;
CREATE TABLE `vle_notifications` (
  `notification_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL COMMENT 'The user who receives this notification',
  `type` varchar(50) NOT NULL COMMENT 'submission, message, enrollment, announcement, grade, forum, finance, system',
  `title` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `link` varchar(500) DEFAULT NULL COMMENT 'URL the notification links to',
  `is_read` tinyint(1) DEFAULT 0,
  `is_emailed` tinyint(1) DEFAULT 0 COMMENT 'Whether this was forwarded to email',
  `related_id` int(11) DEFAULT NULL COMMENT 'ID of related entity (course_id, submission_id, etc.)',
  `related_type` varchar(50) DEFAULT NULL COMMENT 'Type of related entity',
  `created_at` datetime DEFAULT current_timestamp(),
  `read_at` datetime DEFAULT NULL,
  PRIMARY KEY (`notification_id`),
  KEY `idx_user_read` (`user_id`,`is_read`),
  KEY `idx_user_created` (`user_id`,`created_at`),
  KEY `idx_type` (`type`)
) ENGINE=InnoDB AUTO_INCREMENT=64 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_progress
DROP TABLE IF EXISTS `vle_progress`;
CREATE TABLE `vle_progress` (
  `progress_id` int(11) NOT NULL AUTO_INCREMENT,
  `enrollment_id` int(11) DEFAULT NULL,
  `week_number` int(11) DEFAULT NULL,
  `content_id` int(11) DEFAULT NULL,
  `assignment_id` int(11) DEFAULT NULL,
  `progress_type` enum('content_viewed','assignment_completed','week_completed') NOT NULL,
  `completion_date` datetime DEFAULT current_timestamp(),
  `score` decimal(5,2) DEFAULT NULL,
  PRIMARY KEY (`progress_id`),
  KEY `enrollment_id` (`enrollment_id`),
  KEY `content_id` (`content_id`),
  KEY `assignment_id` (`assignment_id`),
  CONSTRAINT `vle_progress_ibfk_1` FOREIGN KEY (`enrollment_id`) REFERENCES `vle_enrollments` (`enrollment_id`),
  CONSTRAINT `vle_progress_ibfk_2` FOREIGN KEY (`content_id`) REFERENCES `vle_weekly_content` (`content_id`),
  CONSTRAINT `vle_progress_ibfk_3` FOREIGN KEY (`assignment_id`) REFERENCES `vle_assignments` (`assignment_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_session_chat
DROP TABLE IF EXISTS `vle_session_chat`;
CREATE TABLE `vle_session_chat` (
  `chat_id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `user_name` varchar(100) NOT NULL,
  `message` text NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`chat_id`),
  KEY `idx_session_time` (`session_id`,`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_session_invites
DROP TABLE IF EXISTS `vle_session_invites`;
CREATE TABLE `vle_session_invites` (
  `invite_id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` int(11) NOT NULL,
  `student_id` varchar(50) NOT NULL,
  `invited_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `viewed_at` timestamp NULL DEFAULT NULL,
  `status` enum('pending','accepted','declined') DEFAULT 'pending',
  PRIMARY KEY (`invite_id`),
  UNIQUE KEY `session_id` (`session_id`,`student_id`),
  KEY `idx_session` (`session_id`),
  KEY `idx_student` (`student_id`)
) ENGINE=InnoDB AUTO_INCREMENT=168 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_session_participants
DROP TABLE IF EXISTS `vle_session_participants`;
CREATE TABLE `vle_session_participants` (
  `participant_id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` int(11) NOT NULL,
  `student_id` varchar(50) NOT NULL,
  `joined_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `left_at` timestamp NULL DEFAULT NULL,
  `status` enum('invited','joined','completed') DEFAULT 'invited',
  PRIMARY KEY (`participant_id`),
  UNIQUE KEY `session_id` (`session_id`,`student_id`),
  KEY `idx_session` (`session_id`),
  KEY `idx_student` (`student_id`)
) ENGINE=InnoDB AUTO_INCREMENT=202 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_session_peers
DROP TABLE IF EXISTS `vle_session_peers`;
CREATE TABLE `vle_session_peers` (
  `peer_id` varchar(100) NOT NULL,
  `session_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `user_name` varchar(100) NOT NULL,
  `user_role` enum('lecturer','student') NOT NULL,
  `is_audio_on` tinyint(1) DEFAULT 1,
  `is_video_on` tinyint(1) DEFAULT 1,
  `is_screen_sharing` tinyint(1) DEFAULT 0,
  `last_heartbeat` timestamp NOT NULL DEFAULT current_timestamp(),
  `joined_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`peer_id`),
  KEY `idx_session` (`session_id`),
  KEY `idx_heartbeat` (`last_heartbeat`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_submissions
DROP TABLE IF EXISTS `vle_submissions`;
CREATE TABLE `vle_submissions` (
  `submission_id` int(11) NOT NULL AUTO_INCREMENT,
  `assignment_id` int(11) DEFAULT NULL,
  `student_id` varchar(20) DEFAULT NULL,
  `submission_date` datetime DEFAULT current_timestamp(),
  `file_path` varchar(500) DEFAULT NULL,
  `file_name` varchar(255) DEFAULT NULL,
  `text_content` text DEFAULT NULL,
  `score` decimal(5,2) DEFAULT NULL,
  `feedback` text DEFAULT NULL,
  `marked_file_path` varchar(255) DEFAULT NULL,
  `marked_file_name` varchar(255) DEFAULT NULL,
  `marked_file_notified` tinyint(1) NOT NULL DEFAULT 0,
  `graded_by` int(11) DEFAULT NULL,
  `graded_date` datetime DEFAULT NULL,
  `status` enum('submitted','graded','late') DEFAULT 'submitted',
  PRIMARY KEY (`submission_id`),
  UNIQUE KEY `assignment_id` (`assignment_id`,`student_id`),
  KEY `student_id` (`student_id`),
  KEY `graded_by` (`graded_by`),
  CONSTRAINT `vle_submissions_ibfk_1` FOREIGN KEY (`assignment_id`) REFERENCES `vle_assignments` (`assignment_id`),
  CONSTRAINT `vle_submissions_ibfk_2` FOREIGN KEY (`student_id`) REFERENCES `students` (`student_id`),
  CONSTRAINT `vle_submissions_ibfk_3` FOREIGN KEY (`graded_by`) REFERENCES `users` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


-- Table: vle_webrtc_signals
DROP TABLE IF EXISTS `vle_webrtc_signals`;
CREATE TABLE `vle_webrtc_signals` (
  `signal_id` int(11) NOT NULL AUTO_INCREMENT,
  `session_id` int(11) NOT NULL,
  `from_peer` varchar(100) NOT NULL,
  `to_peer` varchar(100) NOT NULL,
  `signal_type` enum('offer','answer','ice') NOT NULL,
  `signal_data` longtext NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `is_consumed` tinyint(1) DEFAULT 0,
  PRIMARY KEY (`signal_id`),
  KEY `idx_to_peer` (`to_peer`,`session_id`,`is_consumed`),
  KEY `idx_session` (`session_id`),
  KEY `idx_cleanup` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=450 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Table: vle_week_summaries
DROP TABLE IF EXISTS `vle_week_summaries`;
CREATE TABLE `vle_week_summaries` (
  `summary_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) NOT NULL,
  `week_number` int(11) NOT NULL,
  `main_topics` text DEFAULT NULL,
  `learning_objectives` text DEFAULT NULL,
  `key_concepts` text DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`summary_id`),
  UNIQUE KEY `unique_course_week` (`course_id`,`week_number`),
  KEY `idx_course` (`course_id`),
  KEY `idx_week` (`week_number`),
  CONSTRAINT `vle_week_summaries_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- Table: vle_weekly_content
DROP TABLE IF EXISTS `vle_weekly_content`;
CREATE TABLE `vle_weekly_content` (
  `content_id` int(11) NOT NULL AUTO_INCREMENT,
  `course_id` int(11) DEFAULT NULL,
  `week_number` int(11) NOT NULL,
  `title` varchar(200) NOT NULL,
  `description` text DEFAULT NULL,
  `content_type` enum('presentation','video','document','link','text') DEFAULT 'text',
  `file_path` varchar(500) DEFAULT NULL,
  `file_name` varchar(255) DEFAULT NULL,
  `is_mandatory` tinyint(1) DEFAULT 1,
  `sort_order` int(11) DEFAULT 0,
  `created_date` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`content_id`),
  KEY `course_id` (`course_id`),
  CONSTRAINT `vle_weekly_content_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `vle_courses` (`course_id`)
) ENGINE=InnoDB AUTO_INCREMENT=452 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


SET FOREIGN_KEY_CHECKS = 1;
